var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"내가 지원하고 있는 민간 항공 우주 시설이라네.","JPN":"私が支援している民間空港宇宙施設だ。","ENG":"There's a private aerospace facility that I've been supporting.","TWN":"我有家資助的民用航太設施。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"민간 항공 우주 시설이라고?","JPN":"民間空港宇宙施設だと？","ENG":"A private aerospace facility?","TWN":"民用航太設施？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇네.","JPN":"そうだ。","ENG":"Correct.","TWN":"沒錯。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"관리국의 항공 우주 관제 시설은 지금 적의 공격에 의해서 그 기능이 마비되었거든.","JPN":"管理局の航空宇宙管制施設は今、敵の攻撃によってその機能が麻痺している。","ENG":"You see, the Administration's aerospace control facility is currently down due to the enemy's attack.","TWN":"目前管理局的航太控制設施因為敵方的攻擊都癱瘓了。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"보험인 동시에 어느정도는 투자라고 할 수 있지.","JPN":"保険であると同時に、投資だとも言えるだろう。","ENG":"Consider it a combination of insurance and investment.","TWN":"你可以把它當做一種保險，也是一種投資。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그러고보니…….","JPN":"そういえば……","ENG":"Now that I think of it...","TWN":"這麼一想……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그때, 모더레이터가 공격하고 있던 시설도 관제 시설이었어.","JPN":"あの時、モデレーターが攻撃していた施設も管制施設だった。","ENG":"Yeah, the Moderator's target was also a control facility.","TWN":"當時，被仲裁者攻擊的也是控制設施。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"설마 이런 상황을 예측하고……?","JPN":"まさか、こうなることを予測して……？","ENG":"Did it predict that this would happen...?","TWN":"你該不會也預測到了……？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"으음, 왜 그러지? 내 얼굴에 뭐라도 묻었나?","JPN":"うむ、どうした？　私の顔に何かついているかね？","ENG":"Hmm? What's wrong? Is there something on my face?","TWN":"嗯，怎麼了？我臉上有東西嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"역시 당신…….","JPN":"やっぱりあなた……","ENG":"I guess...","TWN":"你果然……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"최고 관리자라는 말은 거짓말이 아닌 것 같네.","JPN":"最高管理者ってのはウソじゃないみたいだな。","ENG":"you weren't lying when you said you were the Supreme Administrator.","TWN":"是最高管理者，看來不是在撒謊。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"내가 왜 거짓말을 하겠나.","JPN":"私が嘘をつく理由がないさ。","ENG":"Now, why would I lie about that?","TWN":"我為什麼要撒謊？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그 잘나 빠진 하이브 컨트롤 뒤에 관리국을 총괄하는 사람이 있다는 소문을 듣긴 했지만.","JPN":"あのド偉いハイブコントロールの後ろに、管理局を総括する人物がいるってウワサは聞いてたけど……","ENG":"I heard rumors about someone in charge of the Administration behind Hive Control,","TWN":"我有聽過你的傳言，聽說在巢穴控制系統背後，有一個人掌管著管理局。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"상상 이상으로 뻔뻔한 녀석이었잖아?","JPN":"思った以上に図々しいやつだな。","ENG":"but that person turns out to be even more shameless than I expected!","TWN":"但你比我想像得臉皮還要厚。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"후후, 그런 이야기 많이 듣는다네.","JPN":"ふふ、よく言われるよ。","ENG":"Haha, I get that a lot.","TWN":"哈哈，我經常聽人這麼說。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"뭐, 당신에게 묻고 싶은 건 많지만, 지금은 그런 게 중요한 게 아니겠지.","JPN":"ま、あなたに聞きたいことは山ほどあるが、今はそれどころじゃないな。","ENG":"Well, I have loads of questions I want to ask, but that's not what's important right now.","TWN":"好吧，我有很多事情想問你，但現在已經不重要了。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"좋아, 모두를 구할 수만 있다면 당신이 누구인지는 상관없어.","JPN":"よし、みんなを助けられるなら、あなたの正体は関係ない。","ENG":"All right, I don't care who you are as long as I can save everyone.","TWN":"只要能夠拯救所有人，你是誰並不重要。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"야크샤의 우두머리로서 기꺼이 협력하지.","JPN":"ヤクシャーのリーダーとして、喜んで協力しよう。","ENG":"As the head of Yaksha, I'm willing to cooperate.","TWN":"作為夜叉的領袖，我願意配合。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이해해줘서 고맙군.","JPN":"理解してくれてありがとう。","ENG":"Thank you for understanding.","TWN":"感謝你的理解。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그래서? 내가 뭘 하면 되는데?","JPN":"それで？　アタシは何をすればいい？","ENG":"So? What should I do?","TWN":"所以？我應該做些什麼？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"이건……?","JPN":"これは……？","ENG":"What's this...?","TWN":"這是……？"},"stage":{"bg":"MAINSTREAM_5201010","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네가 탑승하게 될 귀환선 모듈이라네. 소유즈 우주선을 베이스로 개량한 버전이지.","JPN":"君が搭乗することになる帰還船モジュールさ。ソユーズ宇宙船をベースに、改良したバージョンだ。","ENG":"This is the reentry capsule module that you'll be riding in. It's based on the Soyuz spacecraft with some modifications.","TWN":"這是你將要搭乘的回程艙模組。是基於聯盟號宇宙船的改量版本。"},"stage":{"bg":"MAINSTREAM_5201010","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"오늘 발사 예정이었던 발사체를 내가 매입해서 발사를 2시간 지연시켰네.","JPN":"今日発射する予定だった発射体を私が買い入れて、発射を2時間引き延ばした。","ENG":"I bought the launch vehicle that was supposed to launch into space today and delayed it by two hours.","TWN":"我收購了原定於今天發射的火箭，並將發射推遲了兩個小時。"},"stage":{"bg":"MAINSTREAM_5201010","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"지금 관리국과의 통신이 가능하도록 라인을 연결하고 있어.","JPN":"今管理局との通信ができるように、ラインを繋げている。","ENG":"Right now, I'm connecting the lines to enable communication with the Administration.","TWN":"目前我正在連接與管理局的通訊。"},"stage":{"bg":"MAINSTREAM_5201010","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"뭐? 오늘 매입했다고?","JPN":"はあ？　今日買い入れた？","ENG":"What? You bought it today?","TWN":"什麼？你今天收購的？"},"stage":{"bg":"MAINSTREAM_5201010","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};